const config = $('Candidate Config').first().json;
const jobs = $input.first().json.data.jobs;

if (!jobs || jobs.length === 0) {
  return [{ json: { error: "No jobs found today", jobs: [] } }];
}

const corridor = config.location.corridor;
const gta = config.location.gta;
const outer_gta = config.location.outer_gta
const locationScores = config.location.scores;
const hardDisqualifiers = config.seniority.hard_disqualifiers;
const juniorSignals = config.seniority.junior_signals;
const expThreshold = config.seniority.experience_threshold_years;

const parsed = jobs.map((job, index) => {
  let desc = (job.job_description || "No description available")
    .replace(/[\r\n\t]+/g, ' ')
    .replace(/"/g, "'")
    .replace(/\\/g, '')
    .replace(/[\x00-\x1F\x7F]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
  const words = desc.split(/\s+/);
  if (words.length > 1200) {
    desc = words.slice(0, 1200).join(" ") + "...";
  }

  // Location fit — deterministic lookup from config
  const cityLower = (job.job_city || "").toLowerCase();
  const countryLower = (job.job_country || "").toLowerCase();
  const isCanada = countryLower === "ca" || countryLower === "canada";
  let locationFitHint;
  if (corridor.includes(cityLower)) locationFitHint = locationScores.corridor;
  else if (gta.includes(cityLower)) locationFitHint = locationScores.gta;
    else if (outer_gta.includes(cityLower)) locationFitHint = locationScores.outer_gta;
  else if (job.job_is_remote && isCanada) locationFitHint = locationScores.remote_canada;
  else if (cityLower === config.location.longterm.toLowerCase()) locationFitHint = locationScores.longterm;
  else if (isCanada) locationFitHint = locationScores.canada_other;
  else if (!cityLower && !countryLower) locationFitHint = locationScores.unknown;
  else locationFitHint = locationScores.outside_canada;

  // Seniority flag — deterministic lookup from config
  const titleLower = (job.job_title || "").toLowerCase();
  let seniorityFlag;
  if (hardDisqualifiers.some(t => titleLower.includes(t))) seniorityFlag = "senior";
  else if (juniorSignals.some(t => titleLower.includes(t))) seniorityFlag = "junior";
  else seniorityFlag = "unknown";

  // Override with description-level experience scan if title looked neutral
  const yearsMatch = desc.match(/(\d{1,2})\+?\s*(?:years|yrs)/i);
  if (yearsMatch && parseInt(yearsMatch[1]) >= expThreshold && seniorityFlag !== "senior") {
    seniorityFlag = "senior";
  }

  return {
    id: index + 1,
    title: job.job_title || "Unknown Title",
    job_id: job.job_id || `fallback-${job.employer_name}-${job.job_title}`.replace(/\s+/g, '-').toLowerCase(),
    company: job.employer_name || "Unknown Company",
    location: job.job_city
      ? `${job.job_city}, ${job.job_state || ""} ${job.job_country || ""}`
      : (job.job_is_remote ? "Remote" : "Not specified"),
    is_remote: job.job_is_remote || false,
    employment_type: job.job_employment_type || "Not specified",
    description: desc,
    apply_link: job.job_apply_link || "#",
    posted: job.job_posted_at_datetime_utc || "Unknown",
    salary_min: job.job_min_salary || null,
    salary_max: job.job_max_salary || null,
    location_fit_hint: locationFitHint,
    seniority_flag: seniorityFlag,
  };
});

return parsed.map(job => ({ json: job }));

const config = $('Candidate Config').first().json;
const weights = config.scoring.weights;
const gates = config.scoring.gates;

const rawContent = $input.first().json.message.content;
const originalJob = $('Loop Over Items').first().json;

let scored;
try {
  scored = JSON.parse(rawContent);
} catch (e) {
  scored = {
    score: 5,
    reason: "Could not parse LLM response. Manual review recommended.",
    key_skills: [],
    experience_level: "unknown",
    salary_estimate: "N/A",
    red_flags: ["LLM parsing failed"],
    dimensions: null
  };
}

// Always override location_fit with the pre-computed value
scored.dimensions = scored.dimensions || {};
scored.dimensions.location_fit = originalJob.location_fit_hint;

// Apply seniority gate — deterministic, not LLM's call
let gated = false;
let gateReason = null;
if (originalJob.seniority_flag === "senior") {
  scored.dimensions.seniority_fit = gates.senior_role_seniority_fit;
  scored.experience_level = "senior"; // override LLM's independent assessment
  gated = true;
  gateReason = "Senior or lead role — outside target seniority";
  if (!scored.red_flags.some(f => f.toLowerCase().includes("senior"))) {
    scored.red_flags.unshift(gateReason);
  }
}

// Compute weighted score from dimensions
const dims = scored.dimensions;
let weightedScore = Math.round(
  (dims.skill_match   || 0) * weights.skill_match +
  (dims.seniority_fit || 0) * weights.seniority_fit +
  (dims.location_fit  || 0) * weights.location_fit +
  (dims.growth_signal || 0) * weights.growth_signal +
  (dims.comp_fit      || 0) * weights.comp_fit
);

// Apply gate ceiling after weighting
if (gated) {
  weightedScore = Math.min(weightedScore, gates.senior_role_max_score);
}

return [{
  json: {
    title: originalJob.title,
    company: originalJob.company,
    location: originalJob.location,
    is_remote: originalJob.is_remote,
    employment_type: originalJob.employment_type,
    apply_link: originalJob.apply_link,
    posted: originalJob.posted,
    salary_min: originalJob.salary_min,
    salary_max: originalJob.salary_max,
    llm_score: scored.score,        // raw LLM holistic score, kept for comparison
    match_score: weightedScore,     // weighted deterministic score, drives sorting/display
    match_reason: scored.reason,
    key_skills: scored.key_skills,
    experience_level: scored.experience_level,
    salary_estimate: scored.salary_estimate,
    red_flags: scored.red_flags,
    dimensions: dims,
    gated: gated,
    gate_reason: gateReason,
  }
}];

const config = $('Candidate Config').first().json;
const allJobs = $input.all().map(item => item.json);

const jobSummaries = allJobs.map(job =>
  `- [Score: ${job.match_score}/10] ${job.title} at ${job.company} (${job.location})
  Reason: ${job.match_reason}
  Skills needed: ${(job.key_skills || []).join(", ")}
  Red flags: ${(job.red_flags || []).length > 0 ? job.red_flags.join(", ") : "None"}`
).join("\n\n");

const requestBody = {
  model: config.models.digest,
  stream: false,
  options: { temperature: config.models.digest_temperature },
  messages: [
    {
      role: "system",
      content: "You are a career assistant agent helping a specific candidate track the job market. Write clearly and directly. Be specific and actionable. Do not pad responses."
    },
    {
      role: "user",
      content: `Below are today's job postings, already scored by relevance to the candidate.

Write a concise daily market summary with these three sections:
1. HEADLINE — one sentence on today's overall market (how many jobs, general quality)
2. TRENDS — patterns across postings (common tools required, seniority mix, remote vs on-site)
3. ACTION ITEMS — two or three specific things the candidate should do today

Do not list, name, or describe individual job postings. A separate ranked table is already included in the email below your summary.

TODAY'S SCORED JOBS:
${jobSummaries}`
    }
  ]
};

return [{ json: { requestBody: JSON.stringify(requestBody), jobs: allJobs } }];

const config = $('Candidate Config').first().json;
const threshold = config.scoring.display_threshold;

const digest = $input.first().json.message.content;
const jobs = $('Prepare Digest Prompt').first().json.jobs;

// If dedup filtered everything, send a short no-new-jobs notice
if (!jobs || jobs.length === 0 || jobs[0]?.no_new_jobs) {
  const today = new Date().toLocaleDateString('en-CA', {
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
  });
  return [{
    json: {
      subject: `Job Digest — ${today} — No new postings`,
      html: `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;">
        <h2 style="color:#1a1a1a;">No New Postings Today</h2>
        <p style="color:#666;">All jobs from today's search have already been seen and scored. 
        Check back tomorrow.</p>
      </div>`
    }
  }];
}

const today = new Date().toLocaleDateString('en-CA', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const rankedJobs = [...jobs].sort((a, b) => b.match_score - a.match_score);
const strongMatches = rankedJobs.filter(j => j.match_score >= threshold);
const topJobs = (strongMatches.length >= 3 ? strongMatches : rankedJobs.slice(0, 3))
  .map(j => {
    const gateLabel = j.gated
      ? `<br/><span style="color:#cc0000;font-size:12px;">⛔ ${j.gate_reason}</span>`
      : "";
    const dimBar = j.dimensions
      ? `<br/><span style="font-size:11px;color:#888;">
          Skill: ${j.dimensions.skill_match}/10 &nbsp;|&nbsp;
          Seniority: ${j.dimensions.seniority_fit}/10 &nbsp;|&nbsp;
          Location: ${j.dimensions.location_fit}/10 &nbsp;|&nbsp;
          Growth: ${j.dimensions.growth_signal}/10
         </span>`
      : "";
    return `<tr>
      <td style="padding:8px;border-bottom:1px solid #eee;">
        <strong>${j.title}</strong><br/>
        ${j.company} — ${j.location}<br/>
        <span style="color:#2d7d46;font-weight:bold;">Score: ${j.match_score}/10</span>
        ${gateLabel}
        ${dimBar}<br/>
        <em>${j.match_reason}</em><br/>
        <a href="${j.apply_link}" style="color:#1a73e8;">Apply Now →</a>
      </td>
    </tr>`;
  }).join("");

const html = `
  <div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;">
    <h1 style="color:#1a1a1a;border-bottom:2px solid #1a73e8;padding-bottom:10px;">
      Job Search Pipeline — Daily Digest
    </h1>
    <p style="color:#666;font-size:14px;">${today} — ${jobs.length} jobs analyzed</p>

    <div style="background:#f8f9fa;padding:16px;border-radius:8px;margin:16px 0;">
      ${digest.replace(/\n/g, "<br/>")}
    </div>

    ${topJobs ? `
    <h2 style="color:#1a1a1a;">Top Matches</h2>
    <table style="width:100%;border-collapse:collapse;">${topJobs}</table>
    ` : "<p>No postings met the display threshold today.</p>"}

    <hr style="margin:24px 0;border:none;border-top:1px solid #eee;"/>
    <p style="color:#999;font-size:12px;">
      Powered by Qwen 2.5 7B (Ollama) + n8n &nbsp;|&nbsp;
      Weighted scoring: Skill ${config.scoring.weights.skill_match * 100}% /
      Seniority ${config.scoring.weights.seniority_fit * 100}% /
      Location ${config.scoring.weights.location_fit * 100}% /
      Growth ${config.scoring.weights.growth_signal * 100}% /
      Comp ${config.scoring.weights.comp_fit * 100}%
    </p>
  </div>`;

return [{
  json: {
    subject: `Job Digest — ${today} — ${jobs.length} jobs, ${strongMatches.length} above threshold`,
    html: html
  }
}];

const config = $('Candidate Config').first().json;
const job = $input.first().json;
const candidate = config.candidate;

const systemPrompt = `You are a job-fit scoring engine for a specific candidate. Score every posting honestly and specifically. Generic praise is a failure; ground every reason in concrete details from the posting.

CANDIDATE PROFILE
- M.Sc. Mathematics (Universal Algebra, Formal Logic, McMaster University). Career switcher into data roles after 6+ years teaching college-level math and statistics.
- Completed Post-Degree Diploma in Data Analytics (Douglas College), 4.33/4.33 GPA.
- Strong skills: ${candidate.strong_skills.join(", ")}.
- Building: ${candidate.building_skills.join(", ")}.
- Gaps, no production experience with: ${candidate.skill_gaps.join(", ")}.
- Target roles in priority order: ${candidate.target_roles.join(", ")}. Strongly prefers coding-heavy engineering work over pure reporting or BI.
- Location: ${config.location.base}. Near-term target market is the London to Kitchener-Waterloo to Toronto corridor. Long-term goal is relocating to ${config.location.longterm}, but that is not the active near-term search market.
- Career stage: ${candidate.career_stage}. This is a career change, not a lateral move. Do not treat teaching seniority as data-role seniority.

SCORING DIMENSIONS, score each 0 to 10
- skill_match: overlap between the tools and skills the posting actually uses day to day and the candidate's real, demonstrated skills.
- seniority_fit: is this reachable for a motivated junior career-switcher with no prior professional data role experience? Any role with "Senior", "Lead", "Principal", "Staff", or "Manager" in the title scores 1. Roles requiring 5+ years of non-teaching professional experience in the core stack score 2-3. Genuinely junior or entry-level roles score 8-10.
- location_fit: a pre-computed value is provided in the job posting block. Copy that number exactly into the location_fit field instead of judging it yourself.
- comp_fit: if a salary range is listed and reasonable for a junior in this field, score high. If clearly below market for the role's real requirements, score low. If no salary is listed, score 5 and do not penalize.
- growth_signal: does this role build toward the candidate's real skill gaps: ${candidate.growth_targets.join(", ")}? Roles that grow those skills score higher.

RULES
- Distinguish required from preferred or nice-to-have language. A missing nice-to-have is not a real gap and should not meaningfully lower skill_match.
- A genuinely load-bearing required skill the candidate lacks entirely should cap the score low. Ask whether the candidate could realistically do the core daily responsibilities on day one, even if imperfectly. If clearly no, reflect that.
- Power BI listed as a requirement is not a hard miss. The candidate has real Tableau depth and Power BI exposure. Treat it as a minor, closeable gap unless the role is explicitly Power BI specialist work with no other visualization tooling.
- score is a holistic 1 to 10 judgment, not a simple average. Weight skill_match and seniority_fit most heavily.
- reason should be 2 to 4 sentences citing specific, concrete details from the actual posting, not generic encouragement.
- red_flags should list real concerns or disqualifiers, empty array if genuinely none. Do not invent concerns to fill space.
- Do not assess seniority or experience level yourself. Do not use the words "junior" or "senior" in the reason field. Seniority is handled externally. Focus reason entirely on skill match and growth signal.`;

const requestBody = {
  model: config.models.scoring,
  stream: false,
  options: { temperature: config.models.scoring_temperature },
  format: {
    type: "object",
    properties: {
      score: { type: "integer", minimum: 1, maximum: 10 },
      reason: { type: "string" },
      key_skills: { type: "array", items: { type: "string" } },
      experience_level: { type: "string", enum: ["junior", "mid", "senior"] },
      salary_estimate: { type: "string" },
      red_flags: { type: "array", items: { type: "string" } },
      dimensions: {
        type: "object",
        properties: {
          skill_match:   { type: "integer", minimum: 0, maximum: 10 },
          seniority_fit: { type: "integer", minimum: 0, maximum: 10 },
          location_fit:  { type: "integer", minimum: 0, maximum: 10 },
          comp_fit:      { type: "integer", minimum: 0, maximum: 10 },
          growth_signal: { type: "integer", minimum: 0, maximum: 10 }
        },
        required: ["skill_match", "seniority_fit", "location_fit", "comp_fit", "growth_signal"]
      }
    },
    required: ["score", "reason", "key_skills", "experience_level", "salary_estimate", "red_flags", "dimensions"]
  },
  messages: [
    {
      role: "system",
      content: systemPrompt
    },
    {
      role: "user",
      content: `JOB POSTING:\nTitle: ${job.title}\nCompany: ${job.company}\nLocation fit (pre-computed, use this exact value for the location_fit dimension, do not re-derive it): ${job.location_fit_hint}/10\nRemote: ${job.is_remote}\nType: ${job.employment_type}\nDescription: ${job.description}`
    }
  ]
};

return [{ json: { requestBody: JSON.stringify(requestBody), job: job } }];

const staticData = $getWorkflowStaticData('global');
const config = $('Candidate Config').first().json;
const TTL_MS = config.search.dedup_ttl_days * 24 * 60 * 60 * 1000;
const now = Date.now();

// Initialize store on first run
if (!staticData.seenJobIds) {
  staticData.seenJobIds = {};
}

const seenIds = staticData.seenJobIds;
const allJobs = $input.all().map(item => item.json);

// Filter to only unseen jobs
const newJobs = allJobs.filter(job => !seenIds[job.job_id]);

// Mark new jobs as seen
for (const job of newJobs) {
  seenIds[job.job_id] = now;
}

// Prune entries older than TTL so the store doesn't grow indefinitely
for (const [id, timestamp] of Object.entries(seenIds)) {
  if (now - timestamp > TTL_MS) {
    delete seenIds[id];
  }
}

// Persist back — required for Static Data to actually save
staticData.seenJobIds = seenIds;

const totalSeen = Object.keys(seenIds).length;

if (newJobs.length === 0) {
  // Return a single item signalling nothing new — Format Email handles this gracefully
  return [{ json: { 
    no_new_jobs: true, 
    message: `No new postings today. ${totalSeen} jobs tracked in seen store.` 
  }}];
}

// Attach dedup metadata for transparency
return newJobs.map(job => ({ 
  json: { 
    ...job, 
    dedup_new: true,
    dedup_store_size: totalSeen
  } 
}));
